import { CheckboxType, type Option } from ':components/Select/Select.types';
import type { FocusEvent, RefObject } from 'react';
import { useCallback, useEffect, useRef, useState } from 'react';

import { useAddArrayIndex } from './components/hooks/useAddArrayIndex';
import { useSelectKeyBoardNavigation } from './components/hooks/useSelectKeyBoardNavigation';
import {
	compareValues,
	defaultRenderValue,
	getCheckboxStatus,
	getOptionsInDisplayOrder,
	getPreparedOptions,
} from './helpers';

export interface UseSelectProps<T> {
	open?: boolean;
	onOpen?: () => void;
	onClose?: () => void;
	onChange: (values: T[], changedItem?: T) => void;
	options: T[];
	values: T[];
	renderValue?: (values: T[]) => string;
	filter?: boolean;
	filterPlaceholder?: string;
	filterFunction?: (options: Array<Option<T>>, filterValue: string) => Array<Option<T>>;
	enableKeyboardNavigation?: boolean;
	multiple?: boolean;
	selectAll?: boolean;
	optionsRef: React.MutableRefObject<HTMLDivElement>;
	inputRef: RefObject<HTMLInputElement>;
	filterRef: RefObject<HTMLInputElement>;
	dropdownRef: RefObject<HTMLDivElement | null>;
	showTooltip?: boolean;
	onFocus?: React.FocusEventHandler<HTMLInputElement>;
	onBlur?: React.FocusEventHandler<HTMLInputElement>;
	selectAllText?: string;
	noOptionsText?: string;
	disabled?: boolean;
	onManualClickOption?: (option: T) => void;
	makeOption?: (option: T, selected?: boolean) => React.JSX.Element;
	loading?: boolean;
	loadingText?: string | React.ReactNode;
	loadingContent?: string | React.ReactNode;
	compareBy?: string | ((a: T, b: T) => boolean);
	groups?: Array<Option<string>>;
}

export const useSelect = <T,>(props: UseSelectProps<T>) => {
	const {
		open,
		onOpen,
		onClose,
		onChange,
		options,
		values,
		renderValue,
		filter,
		filterFunction,
		enableKeyboardNavigation,
		multiple,
		selectAll,
		inputRef,
		filterRef,
		showTooltip,
		onFocus,
		onBlur,
		optionsRef,
		compareBy,
		onManualClickOption,
		dropdownRef,
		groups,
	} = props;

	const [isOpen, setOpen] = useState(open);
	const [filterValue, setFilterValue] = useState('');
	const [disableTooltip, setDisableTooltip] = useState(true);

	const [privateOptions, privateValues] = useAddArrayIndex({ options, values });

	const lastFocusedRef = useRef<HTMLElement | null>(null);

	useEffect(() => {
		const handleFocusIn = (event: FocusEvent): void => {
			if (filterRef.current && filterRef.current.contains(event.target as Node)) {
				lastFocusedRef.current = filterRef.current;
			} else if (inputRef.current && inputRef.current.contains(event.target as Node)) {
				lastFocusedRef.current = inputRef.current;
			}
		};

		document.addEventListener('focusin', handleFocusIn as any);
		return () => {
			document.removeEventListener('focusin', handleFocusIn as any);
		};
	}, [filterRef, inputRef]);

	useEffect(() => {
		if (open !== undefined) {
			setOpen(open);
		}
	}, [open]);

	useEffect(() => {
		setDisableTooltip(showTooltip ? inputRef?.current?.offsetWidth >= inputRef?.current?.scrollWidth : true);
	}, [inputRef, renderValue, values, showTooltip]);

	const handleOpen = (): void => {
		setFilterValue('');
		setOpen(true);
		onOpen?.();
		inputRef.current?.focus();
		setTimeout(() => filter && filterRef.current?.focus(), 100);
	};

	const handleClose = useCallback((): void => {
		if (filter && filterRef.current && lastFocusedRef.current === filterRef.current) {
			const event = {
				target: inputRef.current,
				currentTarget: inputRef.current,
				bubbles: true,
				cancelable: false,
				type: 'blur',
			} as unknown as FocusEvent<HTMLInputElement>;

			onBlur?.(event);
		}
		setFilterValue('');
		setOpen(false);
		onClose?.();
		inputRef.current?.blur();
	}, [setFilterValue, setOpen, onClose, inputRef, filter, filterRef, onBlur]);

	const inputLabel = renderValue ? renderValue(values) : defaultRenderValue<T>(values);

	const onSelectItem = (item: Option<T>) => () => {
		onChange([item.value]);
		handleClose();
	};

	const onMultiselectItem = (item: Option<T>) => () => {
		// Используем compareBy для поиска элемента
		const itemIndex = privateValues.findIndex(value => compareValues(item.value, value.value, compareBy));

		const isAddition = itemIndex === -1;
		const updItems = isAddition ? [...privateValues, item] : privateValues.filter((_value, i) => itemIndex !== i);

		const userValues = updItems.map(item => item.value);
		onChange(userValues, item.value);
	};

	const [focusedIndex, setFocusedIndex] = useSelectKeyBoardNavigation({
		enableKeyboardNavigation,
		isOpen,
		options: privateOptions,
		handleClose,
		multiple,
		optionsRef,
		onMultiselectItem,
		onSelectItem,
		onManualClickOption,
		selectAll,
		inputRef,
		dropdownRef,
		filter,
		filterValue,
		filterFunction,
		groups,
	});
	const keyboardOptions = getOptionsInDisplayOrder(
		getPreparedOptions(privateOptions, filter, filterValue, filterFunction),
		groups,
	);
	const focusedOptionId = focusedIndex >= 0 ? keyboardOptions[focusedIndex]?.id : undefined;

	const handleSelectAll = () => {
		const filteredOptions = getPreparedOptions(privateOptions, filter, filterValue, filterFunction);
		const enabledFilteredOptions = filteredOptions.filter(opt => !opt.disabled);
		const isChecked = getSelectAllStatus() === CheckboxType.CHECKED;

		const checkedFilterFunction = (val: Option<T>) =>
			!enabledFilteredOptions.some(opt => compareValues(opt.value, val.value, compareBy));

		const updatedValues = isChecked
			? privateValues.filter(element => checkedFilterFunction(element))
			: [
					...privateValues,
					...enabledFilteredOptions.filter(
						opt => !privateValues.some(val => compareValues(opt.value, val.value, compareBy)),
					),
				];

		onChange(updatedValues.map(item => item.value));
	};

	const getSelectAllStatus = (): CheckboxType =>
		getCheckboxStatus(privateOptions, privateValues, filterValue, filter, filterFunction, compareBy);

	const changeFilterValue = (value: string): void => {
		setFilterValue(value);
	};

	return {
		isOpen,
		setOpen,
		filterValue,
		setFilterValue,
		disableTooltip,
		privateOptions,
		privateValues,
		inputLabel,
		handleOpen,
		handleClose,
		onSelectItem,
		onMultiselectItem,
		focusedIndex,
		focusedOptionId,
		setFocusedIndex,
		handleSelectAll,
		getSelectAllStatus,
		changeFilterValue,
	};
};
